# agents/agent4_part2_claude_code.py
# Input:  aggregated_report.json + cost_table.json
# Output: 5 professional .docx documents via python-docx

import json
import os
from datetime import date
from pathlib import Path

from docx import Document
from docx.shared import Pt, Inches, RGBColor
from docx.enum.text import WD_ALIGN_PARAGRAPH
from docx.oxml.ns import qn
from docx.oxml import OxmlElement

FOOTER_TEXT = (
    "Generated by AR Engineering Services automated inspection pipeline. "
    "Indicative estimates only. Quantities require physical site measurement. "
    "Not suitable for contractor submission without licensed trade verification."
)

TRADE_ORDER = [
    "demolition contractor", "asbestos removalist", "hazardous materials assessor",
    "pest inspector", "pest and weed control specialist",
    "structural engineer", "licensed builder", "builder",
    "roofer", "roofing contractor",
    "electrician", "licensed electrician",
    "plumber",
    "plasterer",
    "tiler",
    "carpenter", "carpenter/framer",
    "glazier",
    "painter",
    "landscaper",
]

SEVERITY_ORDER = {"Critical": 0, "Moderate": 1, "Minor": 2}

AU_SUPPLIERS = {
    "gyprock": "Gyprock (CSR)", "plasterboard": "Gyprock (CSR)",
    "paint": "Dulux", "primer": "Dulux", "dulux": "Dulux",
    "tile": "Beaumont Tiles", "tiling": "Beaumont Tiles",
    "pipe": "Reece", "tapware": "Reece", "drain": "Reece",
    "electrical": "Rexel / Middy's", "cable": "Rexel / Middy's", "wiring": "Rexel / Middy's",
    "colorbond": "Bluescope Steel", "roofing": "Bluescope Steel",
    "timber": "Bunnings", "framing": "Bunnings", "concrete": "Boral",
    "render": "Boral", "brick": "Boral",
}


# ── Helpers ────────────────────────────────────────────────────────────────

def _set_cell_bg(cell, hex_color: str):
    tc = cell._tc
    tcPr = tc.get_or_add_tcPr()
    shd = OxmlElement("w:shd")
    shd.set(qn("w:fill"), hex_color)
    shd.set(qn("w:val"), "clear")
    tcPr.append(shd)


def _bold_row(row):
    for cell in row.cells:
        for para in cell.paragraphs:
            for run in para.runs:
                run.bold = True


def _add_footer(doc: Document):
    for section in doc.sections:
        footer = section.footer
        p = footer.paragraphs[0] if footer.paragraphs else footer.add_paragraph()
        p.clear()
        run = p.add_run(FOOTER_TEXT)
        run.font.size = Pt(7)
        run.font.color.rgb = RGBColor(0x80, 0x80, 0x80)
        p.alignment = WD_ALIGN_PARAGRAPH.CENTER


def _doc_title(doc: Document, title: str, property_id: str):
    today = date.today().strftime("%d/%m/%Y")
    h = doc.add_heading(title, level=1)
    h.alignment = WD_ALIGN_PARAGRAPH.LEFT
    sub = doc.add_paragraph()
    sub.add_run(f"AR Engineering Services Pty Ltd  |  Property: {property_id.upper()}  |  Date: {today}")
    sub.runs[0].font.size = Pt(10)
    sub.runs[0].font.color.rgb = RGBColor(0x44, 0x44, 0x44)
    doc.add_paragraph()


def _table_header(table, headers: list, bg: str = "1F3864"):
    hdr = table.rows[0].cells
    for i, h in enumerate(headers):
        hdr[i].text = h
        for para in hdr[i].paragraphs:
            for run in para.runs:
                run.bold = True
                run.font.color.rgb = RGBColor(0xFF, 0xFF, 0xFF)
                run.font.size = Pt(9)
        _set_cell_bg(hdr[i], bg)


def _sort_trades(trade_set):
    return sorted(trade_set, key=lambda t: next(
        (i for i, x in enumerate(TRADE_ORDER) if x == t.lower()), 99
    ))


# ── 01 Scope of Works ──────────────────────────────────────────────────────

def _make_scope(report: dict, property_id: str, out_path: Path):
    doc = Document()
    _doc_title(doc, "01 — Scope of Works", property_id)

    doc.add_paragraph(
        "This Scope of Works has been prepared based on an automated video inspection of the "
        f"subject property. A total of {report['total_frames_analysed']} inspection frames were "
        f"analysed across {len(report['rooms'])} areas. "
        f"{report['defect_summary']['total']} defects were identified: "
        f"{report['defect_summary']['critical']} Critical, "
        f"{report['defect_summary']['moderate']} Moderate, "
        f"{report['defect_summary']['minor']} Minor."
    )
    doc.add_paragraph()

    # Group defects by trade
    trade_items: dict[str, list] = {}
    for room_key, room_data in report["rooms"].items():
        room_label = room_key.replace("_", " ").title()
        for defect in room_data["defects"]:
            trades = room_data.get("trades_required") or ["builder"]
            trade = trades[0].lower() if trades else "builder"
            trade_items.setdefault(trade, []).append({
                "room": room_label,
                "name": defect["name"],
                "severity": defect["severity"],
                "action": defect["action"],
            })

    doc.add_heading("Scope by Trade — Australian Sequence", level=2)

    for trade in _sort_trades(trade_items.keys()):
        items = trade_items[trade]
        doc.add_heading(trade.title(), level=3)
        for item in items:
            sev_tag = f"[{item['severity']}]"
            p = doc.add_paragraph(style="List Bullet")
            run = p.add_run(f"{sev_tag} {item['name']} — {item['room']}: ")
            run.bold = True
            if item["severity"] == "Critical":
                run.font.color.rgb = RGBColor(0xC0, 0x00, 0x00)
            elif item["severity"] == "Moderate":
                run.font.color.rgb = RGBColor(0xC0, 0x60, 0x00)
            p.add_run(item["action"])

    doc.add_paragraph()
    note = doc.add_paragraph()
    note.add_run("Critical Dependencies: ").bold = True
    note.add_run(
        "All structural engineer assessments must be completed before framing works commence. "
        "Asbestos and hazardous materials testing must be completed before any demolition or sanding. "
        "Electrical and plumbing rough-in must be completed before Gyprock installation."
    )

    doc.add_paragraph()
    seq = doc.add_paragraph()
    seq.add_run("Trade Sequence: ").bold = True
    seq.add_run(
        "Demolition → Pest / Hazmat → Structural → Roof → Electrical rough-in → "
        "Plumbing rough-in → Plasterboard → Tiling → Painting → Fix-off"
    )

    _add_footer(doc)
    doc.save(out_path)


# ── 02 Cost Estimate ───────────────────────────────────────────────────────

def _make_cost(cost_table: dict, property_id: str, out_path: Path):
    doc = Document()
    _doc_title(doc, "02 — Cost Estimate", property_id)

    doc.add_paragraph(
        f"All figures in Australian Dollars (AUD) inclusive of GST at {cost_table['gst_rate']}. "
        f"Prepared: {cost_table['generated_date']}. "
        "Electrician items require licensed trade quote — excluded from totals below."
    )
    doc.add_paragraph()

    cols = ["ID", "Defect", "Trade", "Sev.", "Hrs Min", "Hrs Max",
            "Cost ex-GST Min", "Cost ex-GST Max", "Total inc-GST Min", "Total inc-GST Max", "Flag"]
    table = doc.add_table(rows=1, cols=len(cols))
    table.style = "Table Grid"
    _table_header(table, cols)

    current_trade = None
    for item in cost_table["line_items"]:
        if item["trade"] != current_trade:
            current_trade = item["trade"]
            sep = table.add_row().cells
            sep[0].text = current_trade.title()
            sep[0].paragraphs[0].runs[0].bold = True
            for c in sep:
                _set_cell_bg(c, "D9E1F2")
            for i in range(1, len(cols)):
                sep[i].text = ""

        row = table.add_row().cells
        row[0].text = item["defect_id"]
        row[1].text = item["defect"]
        row[2].text = item["trade"].title()
        row[3].text = item["severity"]

        if item.get("flag") == "REQUIRES_TRADE_QUOTE":
            row[4].text = "—"
            row[5].text = "—"
            row[6].text = "Requires licensed trade inspection and quote — not included in estimate"
            row[7].text = ""
            row[8].text = ""
            row[9].text = ""
            row[10].text = "TRADE QUOTE"
        else:
            row[4].text = str(item.get("hours_min", ""))
            row[5].text = str(item.get("hours_max", ""))
            row[6].text = f"${item['cost_min']:,.2f}" if item.get("cost_min") is not None else ""
            row[7].text = f"${item['cost_max']:,.2f}" if item.get("cost_max") is not None else ""
            row[8].text = f"${item['total_min']:,.2f}" if item.get("total_min") is not None else ""
            row[9].text = f"${item['total_max']:,.2f}" if item.get("total_max") is not None else ""
            row[10].text = item.get("flag") or ""

        for cell in row:
            for para in cell.paragraphs:
                for run in para.runs:
                    run.font.size = Pt(8)

    doc.add_paragraph()

    # Subtotals by trade
    doc.add_heading("Subtotals by Trade", level=2)
    st = doc.add_table(rows=1, cols=3)
    st.style = "Table Grid"
    _table_header(st, ["Trade", "Min (ex-GST)", "Max (ex-GST)"])
    for trade, vals in cost_table["subtotals_by_trade"].items():
        r = st.add_row().cells
        r[0].text = trade.title()
        r[1].text = f"${vals['min']:,.2f}"
        r[2].text = f"${vals['max']:,.2f}"

    doc.add_paragraph()

    # Grand totals
    totals_data = [
        ("Total ex-GST",     cost_table["total_ex_gst"]),
        (f"GST ({cost_table['gst_rate']})",  cost_table["gst_amount"]),
        ("GRAND TOTAL inc-GST", cost_table["total_inc_gst"]),
    ]
    for label, vals in totals_data:
        p = doc.add_paragraph()
        run = p.add_run(f"{label}:   ${vals['min']:,.2f}  –  ${vals['max']:,.2f} AUD")
        run.bold = True
        if label.startswith("GRAND"):
            run.font.size = Pt(13)
            run.font.color.rgb = RGBColor(0x1F, 0x38, 0x64)

    doc.add_paragraph()
    note = doc.add_paragraph()
    note.add_run("Note: ").bold = True
    note.add_run(
        "Items flagged REQUIRES_SITE_MEASURE are indicative only — final quantities subject to "
        "physical site measurement. Electrician items excluded pending licensed trade quote."
    )

    _add_footer(doc)
    doc.save(out_path)


# ── 03 Material List ───────────────────────────────────────────────────────

def _make_materials(report: dict, property_id: str, out_path: Path):
    doc = Document()
    _doc_title(doc, "03 — Material List", property_id)

    doc.add_paragraph(
        "Materials identified during automated video inspection. Quantities require physical "
        "site measurement. Australian supplier references are indicative only."
    )
    doc.add_paragraph()

    table = doc.add_table(rows=1, cols=4)
    table.style = "Table Grid"
    _table_header(table, ["Room", "Material", "Suggested Supplier (AU)", "Notes"])

    for room_key, room_data in report["rooms"].items():
        room_label = room_key.replace("_", " ").title()
        mats = room_data.get("materials_identified", [])
        if not mats:
            continue
        for i, mat in enumerate(mats):
            row = table.add_row().cells
            row[0].text = room_label if i == 0 else ""
            row[1].text = mat.title()
            supplier = next(
                (v for k, v in AU_SUPPLIERS.items() if k in mat.lower()),
                "Bunnings / trade supplier"
            )
            row[2].text = supplier
            row[3].text = "Qty TBC — site measure required"
            for cell in row:
                for para in cell.paragraphs:
                    for run in para.runs:
                        run.font.size = Pt(9)

    _add_footer(doc)
    doc.save(out_path)


# ── 04 Trade Schedule ──────────────────────────────────────────────────────

def _make_schedule(cost_table: dict, property_id: str, out_path: Path):
    doc = Document()
    _doc_title(doc, "04 — Trade Schedule", property_id)

    doc.add_paragraph(
        "Sequenced in accordance with Australian building trade practice. "
        "Durations estimated at 8-hour working days from cost table hours. "
        "Start and completion dates to be confirmed at contract award."
    )
    doc.add_paragraph()

    by_trade: dict[str, dict] = {}
    for item in cost_table["line_items"]:
        t = item["trade"]
        if t not in by_trade:
            by_trade[t] = {"hours_min": 0, "hours_max": 0, "items": []}
        by_trade[t]["items"].append(item["defect"])
        if item.get("hours_min"):
            by_trade[t]["hours_min"] += item["hours_min"]
            by_trade[t]["hours_max"] += item["hours_max"]

    ordered = _sort_trades(by_trade.keys())

    table = doc.add_table(rows=1, cols=6)
    table.style = "Table Grid"
    _table_header(table, ["#", "Trade", "Scope Summary", "Est. Days", "Start Date", "Dependency"])

    prev_trade = "Site access / mobilisation"
    for seq_num, trade in enumerate(ordered, 1):
        data = by_trade[trade]
        days_min = max(1, data["hours_min"] // 8)
        days_max = max(1, data["hours_max"] // 8)
        duration = f"{days_min}" if days_min == days_max else f"{days_min}–{days_max}"

        items_preview = data["items"][:3]
        scope = "; ".join(items_preview)
        if len(data["items"]) > 3:
            scope += f" + {len(data['items']) - 3} more"

        row = table.add_row().cells
        row[0].text = str(seq_num)
        row[1].text = trade.title()
        row[2].text = scope
        row[3].text = f"{duration} day(s)"
        row[4].text = "DD/MM/YYYY"
        row[5].text = prev_trade.title()
        prev_trade = trade

        for cell in row:
            for para in cell.paragraphs:
                for run in para.runs:
                    run.font.size = Pt(9)

    doc.add_paragraph()
    note = doc.add_paragraph()
    note.add_run("Important: ").bold = True
    note.add_run(
        "Structural engineer sign-off required before framing or roof replacement commences. "
        "All hazardous materials (asbestos, lead paint) must be cleared before trades begin work. "
        "Electrical and plumbing rough-in must precede Gyprock installation."
    )

    _add_footer(doc)
    doc.save(out_path)


# ── 05 Defect Log ──────────────────────────────────────────────────────────

def _make_defects(cost_table: dict, report: dict, property_id: str, out_path: Path):
    doc = Document()
    _doc_title(doc, "05 — Defect Log", property_id)

    summary = report["defect_summary"]
    doc.add_paragraph(
        f"Total defects identified: {summary['total']}  |  "
        f"Critical: {summary['critical']}  |  "
        f"Moderate: {summary['moderate']}  |  "
        f"Minor: {summary['minor']}"
    ).runs[0].bold = True
    doc.add_paragraph()

    items = sorted(
        cost_table["line_items"],
        key=lambda x: SEVERITY_ORDER.get(x["severity"], 9)
    )

    SEV_COLORS = {"Critical": "FCE4D6", "Moderate": "FFEB9C", "Minor": "EBFBEE"}

    table = doc.add_table(rows=1, cols=7)
    table.style = "Table Grid"
    _table_header(table, ["ID", "Defect", "Severity", "Location", "Recommended Action",
                           "Trade", "Est. Cost inc-GST (AUD)"])

    for item in items:
        row = table.add_row().cells
        row[0].text = item["defect_id"]
        row[1].text = item["defect"]
        row[2].text = item["severity"]
        row[3].text = item["room"]
        row[4].text = item["action"]
        row[5].text = item["trade"].title()

        if item.get("flag") == "REQUIRES_TRADE_QUOTE":
            row[6].text = "Trade quote required"
        elif item.get("total_min") is not None:
            row[6].text = f"${item['total_min']:,.2f} – ${item['total_max']:,.2f}"
        else:
            row[6].text = "—"

        bg = SEV_COLORS.get(item["severity"], "FFFFFF")
        _set_cell_bg(row[2], bg)

        for cell in row:
            for para in cell.paragraphs:
                for run in para.runs:
                    run.font.size = Pt(8)

    _add_footer(doc)
    doc.save(out_path)


# ── Entry point ────────────────────────────────────────────────────────────

def run_agent4_documents(aggregated_path: str, cost_table_path: str, output_folder: str) -> bool:
    os.makedirs(output_folder, exist_ok=True)
    out = Path(output_folder)

    with open(aggregated_path, encoding="utf-8") as f:
        report = json.load(f)
    with open(cost_table_path, encoding="utf-8") as f:
        cost_table = json.load(f)

    property_id = report.get("property_id", "input")

    tasks = [
        ("01_Scope_of_Works.docx",  _make_scope,     (report, property_id)),
        ("02_Cost_Estimate.docx",   _make_cost,      (cost_table, property_id)),
        ("03_Material_List.docx",   _make_materials, (report, property_id)),
        ("04_Trade_Schedule.docx",  _make_schedule,  (cost_table, property_id)),
        ("05_Defect_Log.docx",      _make_defects,   (cost_table, report, property_id)),
    ]

    print("\n[Agent 4] Generating 5 documents...")
    for filename, fn, args in tasks:
        fn(*args, out / filename)
        print(f"[Agent 4] Saved: {filename}")

    print("[Agent 4] Complete — 5 documents generated")
    return True
